// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx (vẫn dùng để đọc CSV)
import './KhaiBaoCoSo.css'; // Import file CSS

function KhaiBaoCoSo() {
  // Initial form state for resetting
  const initialFormState = {
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '', // Thêm tongDan
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '', // Thêm khoiLuong
    loaiCoSoDangKy: '', 
  };

  const [form, setForm] = useState(initialFormState);
  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  const [csvFile, setCsvFile] = useState(null); // Đổi tên state từ excelFile sang csvFile
  const [excelData, setExcelData] = useState([]); // Vẫn giữ tên excelData vì logic ánh xạ không đổi
  const [isLoading, setIsLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    setIsAdmin(true); // Giả định là admin cho mục đích demo
  }, []);

  const resetForm = useCallback(() => {
    setForm(initialFormState);
    setSuccessMessage('');
    setErrorMessage('');
  }, [initialFormState]);

  const resetCsvUpload = useCallback(() => { // Đổi tên hàm resetExcelUpload
    setCsvFile(null);
    setExcelData([]);
    setSuccessMessage('');
    setErrorMessage('');
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const validateForm = () => {
    setSuccessMessage('');
    setErrorMessage('');

    const isGayNuoiFilled = (form.mucDichNuoi && form.mucDichNuoi.trim() !== '') || 
                           (form.hinhThucNuoi && form.hinhThucNuoi.trim() !== '') || 
                           (form.maSoCoSoGayNuoi && form.maSoCoSoGayNuoi.trim() !== '') ||
                           (form.tongDan && String(form.tongDan).trim() !== ''); // Kiểm tra tongDan

    const isKinhDoanhGoFilled = (form.loaiHinhKinhDoanhGo && form.loaiHinhKinhDoanhGo.trim() !== '') ||
                               (form.nganhNgheKinhDoanhGo && form.nganhNgheKinhDoanhGo.trim() !== '') ||
                               (form.khoiLuong && String(form.khoiLuong).trim() !== ''); // Kiểm tra khoiLuong

    if (form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi') {
      if (!isGayNuoiFilled) {
        setErrorMessage('Vui lòng điền đầy đủ thông tin cho mục "Cơ sở gây nuôi".');
        return false;
      }
      if (isKinhDoanhGoFilled) {
        setErrorMessage('Không được điền thông tin "Cơ sở kinh doanh, chế biến gỗ" khi đã chọn "Đăng ký cơ sở gây nuôi".');
        return false;
      }
    } else if (form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') {
      if (!isKinhDoanhGoFilled) {
        setErrorMessage('Vui lòng điền đầy đủ thông tin cho mục "Cơ sở kinh doanh, chế biến gỗ".');
        return false;
      }
      if (isGayNuoiFilled) {
        setErrorMessage('Không được điền thông tin "Cơ sở gây nuôi" khi đã chọn "Đăng ký cơ sở kinh doanh, chế biến gỗ".');
        return false;
      }
    } else {
      if (isGayNuoiFilled && isKinhDoanhGoFilled) {
        setErrorMessage('Bạn chỉ có thể khai báo thông tin cho Cơ sở gây nuôi HOẶC Cơ sở kinh doanh, chế biến gỗ, không được cả hai.');
        return false;
      }
      if (!isGayNuoiFilled && !isKinhDoanhGoFilled) {
        setErrorMessage('Vui lòng chọn "Loại cơ sở đăng ký" và điền thông tin tương ứng.');
        return false;
      }
    }
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsLoading(true);
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        setIsLoading(false);
        return;
      }

      const response = await axios.post(
        'http://localhost:10000/api/farms',
        form,
        { headers: { Authorization: `Bearer ${token}` } }
      );

      console.log('Success:', response.data);
      setSuccessMessage('Thông tin cơ sở đã được lưu thành công!');
      resetForm();
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi lưu thông tin. Vui lòng thử lại.');
      console.error('Error saving farm:', error.response?.data || error.message);
      if (error.response && error.response.data && error.response.data.errors) {
        const validationErrors = Object.values(error.response.data.errors).map(err => err.message).join('; ');
        setErrorMessage(`Lỗi xác thực: ${validationErrors}`);
      } else if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Đã xảy ra lỗi: ${error.response.data.message}`);
      }
    } finally {
      setIsLoading(false);
    }
  };

  // Helper function to parse date strings (DD/MM/YYYY) from CSV
  const parseDateFromCsv = (dateString) => {
    if (!dateString) return '';

    // Attempt to parse as Excel serial number first (if it's a number)
    if (typeof dateString === 'number') {
      const date = new Date(Math.round((dateString - 25569) * 86400 * 1000));
      return isNaN(date.getTime()) ? '' : date.toISOString().split('T')[0];
    }

    // Attempt to parse as DD/MM/YYYY string
    const dateStr = String(dateString).trim(); // Trim whitespace
    const parts = dateStr.split('/');
    if (parts.length === 3) {
      const day = parseInt(parts[0], 10);
      const month = parseInt(parts[1], 10) - 1; // Month is 0-indexed for Date constructor
      const year = parseInt(parts[2], 10);

      const date = new Date(year, month, day); // Use year, monthIndex, day constructor
      
      // Check if date is valid before converting to ISO string
      return isNaN(date.getTime()) ? '' : date.toISOString().split('T')[0];
    }

    // If neither format matches, return empty string
    return '';
  };

  // Function to handle CSV file upload
  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setCsvFile(file); // Cập nhật state csvFile
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const data = event.target.result; // Đọc nội dung file CSV dưới dạng chuỗi
          
          // Sử dụng type: 'string' và sau đó parse CSV
          // Thêm delimiter: ',' nếu CSV của bạn sử dụng dấu phẩy làm dấu phân cách
          // hoặc delimiter: ';' nếu sử dụng dấu chấm phẩy
          const workbook = XLSX.read(data, { type: 'string', cellDates: true, FS: ',' }); // FS là Field Separator cho CSV

          const sheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[sheetName];
          
          // Sử dụng header: 1 để đảm bảo dòng đầu tiên được đọc làm tiêu đề
          // và raw: false để đảm bảo giá trị được parse đúng kiểu (ví dụ: số, ngày)
          const json = XLSX.utils.sheet_to_json(worksheet, { header: 1, raw: false }); 

          console.log("Raw JSON data from CSV (from XLSX.utils.sheet_to_json):", json); // LOG QUAN TRỌNG

          // Xác định tiêu đề từ dòng đầu tiên
          const headers = json[0];
          console.log("Detected Headers:", headers); // LOG: Tiêu đề được phát hiện

          // Lấy dữ liệu từ các dòng còn lại
          const dataRows = json.slice(1);
          console.log("Data Rows (excluding header):", dataRows); // LOG: Các hàng dữ liệu

          const mappedData = dataRows.map(rowData => {
            const farm = {}; // Tạo đối tượng farm rỗng

            // Hàm helper để lấy giá trị từ hàng dữ liệu bằng cách tìm chỉ số của tiêu đề
            const getCellValue = (headerName) => {
              const index = headers.indexOf(headerName);
              // Trả về giá trị nếu tìm thấy, nếu không thì undefined
              return index !== -1 ? rowData[index] : undefined; 
            };

            // Hàm helper để thêm trường vào đối tượng nếu có giá trị (cho các trường không bắt buộc)
            const addFieldIfNotEmpty = (key, value) => {
              if (value !== null && value !== undefined && String(value).trim() !== '') {
                farm[key] = value;
              }
            };

            // Các trường BẮT BUỘC: Luôn gán giá trị, ngay cả khi trống, để Mongoose có thể validate
            farm.tenCoSo = getCellValue('Tên cơ sở') || '';
            farm.tenNguoiDaiDien = getCellValue('Họ và tên') || '';
            farm.soCCCD = getCellValue('Số CCCD/Hộ chiếu') || '';
            farm.loaiCoSoDangKy = getCellValue('loại cơ sở đăng ký') || ''; // Chú ý chữ 'l' thường

            // Các trường KHÔNG BẮT BUỘC: Chỉ thêm nếu có giá trị
            addFieldIfNotEmpty('tinhThanhPho', getCellValue('Tỉnh (Thành phố)'));
            addFieldIfNotEmpty('xaPhuong', getCellValue('Xã (Phường)'));
            addFieldIfNotEmpty('diaChiCoSo', getCellValue('Địa chỉ'));
            addFieldIfNotEmpty('vido', getCellValue('Vĩ độ'));
            addFieldIfNotEmpty('kinhdo', getCellValue('Kinh độ'));
            addFieldIfNotEmpty('loaiHinhCoSo', getCellValue('Loại hình cơ sở'));
            addFieldIfNotEmpty('ngayThanhLap', parseDateFromCsv(getCellValue('Ngày thành lập')));
            addFieldIfNotEmpty('giayPhepKinhDoanh', getCellValue('Số giấy phép'));
            addFieldIfNotEmpty('namSinh', getCellValue('Năm sinh'));
            addFieldIfNotEmpty('ngayCapCCCD', parseDateFromCsv(getCellValue('Ngày cấp')));
            addFieldIfNotEmpty('noiCapCCCD', getCellValue('Nơi cấp'));
            addFieldIfNotEmpty('soDienThoaiNguoiDaiDien', getCellValue('Số điện thoại'));
            addFieldIfNotEmpty('diaChiNguoiDaiDien', getCellValue('Địa chỉ người đại diện'));
            addFieldIfNotEmpty('emailNguoiDaiDien', getCellValue('Email người đại diện'));
            
            // Thêm trường mới cho Cơ sở gây nuôi
            addFieldIfNotEmpty('mucDichNuoi', getCellValue('Mục đích nuôi'));
            addFieldIfNotEmpty('hinhThucNuoi', getCellValue('Hình thức nuôi'));
            addFieldIfNotEmpty('maSoCoSoGayNuoi', getCellValue('Mã số cơ sở gây nuôi'));
            addFieldIfNotEmpty('tongDan', getCellValue('Tổng đàn')); // Thêm trường Tổng đàn

            // Thêm trường mới cho Cơ sở kinh doanh, chế biến gỗ
            addFieldIfNotEmpty('loaiHinhKinhDoanhGo', getCellValue('Loại hình kinh doanh gỗ'));
            addFieldIfNotEmpty('nganhNgheKinhDoanhGo', getCellValue('Ngành nghề kinh doanh gỗ'));
            addFieldIfNotEmpty('khoiLuong', getCellValue('Khối lượng')); // Thêm trường Khối lượng

            return farm;
          });
          setExcelData(mappedData); // Vẫn dùng setExcelData
          setSuccessMessage(`Đã đọc thành công ${dataRows.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.`);
          setErrorMessage('');
        } catch (error) {
          setErrorMessage('Lỗi khi đọc file CSV. Vui lòng đảm bảo file đúng định dạng và có các cột tiêu đề phù hợp.');
          console.error('Error reading CSV file:', error);
        }
      };
      reader.readAsText(file); // Đọc file CSV dưới dạng văn bản (text)
    }
  };

  const handleBulkSubmit = async () => {
    setSuccessMessage('');
    setErrorMessage('');

    if (excelData.length === 0) {
      setErrorMessage('Không có dữ liệu từ CSV để tải lên.');
      return;
    }

    setIsLoading(true);
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        setIsLoading(false);
        return;
      }

      const response = await axios.post(
        'http://localhost:10000/api/farms/bulk',
        excelData,
        { headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' } }
      );

      console.log('Bulk upload success:', response.data);
      setSuccessMessage(`Đã lưu thành công ${response.data.savedCount || excelData.length} cơ sở từ file CSV!`);
      resetCsvUpload(); // Gọi hàm resetCsvUpload
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi tải lên dữ liệu hàng loạt. Vui lòng thử lại.');
      console.error('Error bulk uploading farms:', error.response?.data || error.message);

      if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Lỗi: ${error.response.data.message}`);
      } else if (error.response && error.response.data && error.response.data.errors) {
        const validationErrors = Object.values(error.response.data.errors).map(err => err.message).join('; ');
        setErrorMessage(`Lỗi xác thực: ${error.response.data.message || 'Một số bản ghi không hợp lệ.'}`);
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="khai-bao-container">
      <h1>Khai báo cơ sở</h1>
      
      {isLoading && <p className="loading-message">Đang xử lý...</p>}
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      
      <form onSubmit={handleSubmit}>
        <section className="khai-bao-section">
          <h2>Thông tin cơ sở (Khai báo thủ công)</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenCoSo">Tên cơ sở:</label>
              <input type="text" id="tenCoSo" name="tenCoSo" value={form.tenCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
              <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={form.tinhThanhPho} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="xaPhuong">Xã (Phường):</label>
              <input type="text" id="xaPhuong" name="xaPhuong" value={form.xaPhuong} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiCoSo">Địa chỉ:</label>
              <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={form.diaChiCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="vido">Vĩ độ:</label>
              <input type="text" id="vido" name="vido" value={form.vido} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="kinhdo">Kinh độ:</label>
              <input type="text" id="kinhdo" name="kinhdo" value={form.kinhdo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="loaiHinhCoSo">Loại hình cơ sở:</label>
              <input type="text" id="loaiHinhCoSo" name="loaiHinhCoSo" value={form.loaiHinhCoSo} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
              <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={form.ngayThanhLap} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="giayPhepKinhDoanh">Số giấy phép kinh doanh:</label>
              <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={form.giayPhepKinhDoanh} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="loaiCoSoDangKy">Loại cơ sở đăng ký:</label>
              <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={form.loaiCoSoDangKy} onChange={handleChange} required>
                <option value="">- Chọn loại cơ sở -</option>
                <option value="Đăng ký cơ sở gây nuôi">=> Đăng ký cơ sở gây nuôi</option>
                <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">=> Đăng ký cơ sở kinh doanh,chế biến gỗ</option>
              </select>
            </div>
          </div>
        </section>

        <section className="khai-bao-section">
          <h2>Người đại diện</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenNguoiDaiDien">Họ và tên:</label>
              <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={form.tenNguoiDaiDien} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="namSinh">Năm sinh:</label>
              <input type="number" id="namSinh" name="namSinh" value={form.namSinh} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="soCCCD">Số CCCD/Hộ chiếu:</label>
              <input type="text" id="soCCCD" name="soCCCD" value={form.soCCCD} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="ngayCapCCCD">Ngày cấp:</label>
              <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={form.ngayCapCCCD} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="noiCapCCCD">Nơi cấp:</label>
              <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={form.noiCapCCCD} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại:</label>
              <input type="tel" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={form.soDienThoaiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiNguoiDaiDien">Địa chỉ:</label>
              <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={form.diaChiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="emailNguoiDaiDien">Email:</label>
              <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={form.emailNguoiDaiDien} onChange={handleChange} />
            </div>
          </div>
        </section>

        {form.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <section className="khai-bao-section">
            <h3>Cơ sở gây nuôi</h3>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
                <select id="mucDichNuoi" name="mucDichNuoi" value={form.mucDichNuoi} onChange={handleChange}>
                  <option value="">Chọn mục đích nuôi</option>
                  <option value="Nuôi thương mại">Nuôi thương mại</option>
                  <option value="Nuôi phi thương mại">Nuôi phi thương mại</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
                <select id="hinhThucNuoi" name="hinhThucNuoi" value={form.hinhThucNuoi} onChange={handleChange}>
                  <option value="">Chọn hình thức nuôi</option>
                  <option value="Sinh trưởng">Sinh trưởng</option>
                  <option value="Sinh sản">Sinh sản</option>
                  <option value="Sinh trưởng và sinh sản">Sinh trưởng và sinh sản</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở:</label>
                <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={form.maSoCoSoGayNuoi} onChange={handleChange} />
              </div>
              <div className="form-group"> {/* Thêm trường Tổng đàn */}
                <label htmlFor="tongDan">Tổng đàn:</label>
                <input type="number" id="tongDan" name="tongDan" value={form.tongDan} onChange={handleChange} />
              </div>
            </div>
          </section>
        )}

        {form.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
          <section className="khai-bao-section">
            <h4>Cơ sở kinh doanh, chế biến gỗ</h4>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
                <select id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={form.loaiHinhKinhDoanhGo} onChange={handleChange}>
                  <option value="">Chọn loại hình kinh doanh</option>
                  <option value="Trại cưa">Trại cưa</option>
                  <option value="Trại mộc">Trại mộc</option>
                  <option value="Trang trí nội thất">Trang trí nội thất</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề:</label>
                <select id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={form.nganhNgheKinhDoanhGo} onChange={handleChange}>
                  <option value="">Chọn ngành nghề</option>
                  <option value="Thương mại">Thương mại</option>
                  <option value="Cưa gia công và mộc">Cưa gia công và mộc</option>
                  <option value="Chế biến mộc và thương mại">Chế biến mộc và thương mại</option>
                </select>
              </div>
              <div className="form-group"> {/* Thêm trường Khối lượng */}
                <label htmlFor="khoiLuong">Khối lượng:</label>
                <input type="text" id="khoiLuong" name="khoiLuong" value={form.khoiLuong} onChange={handleChange} />
              </div>
            </div>
          </section>
        )}

        <button type="submit" className="submit-button" disabled={isLoading}>
          {isLoading ? 'Đang lưu...' : 'Lưu thông tin'}
        </button>
      </form>

      {isAdmin && <hr className="section-divider" />}

      {isAdmin && (
        <section className="khai-bao-section excel-upload-section">
          <div className="file-upload-group">
            <label htmlFor="csvUpload" className="file-upload-label">
              Chọn file CSV (.csv):
            </label>
            <input 
              type="file" 
              id="csvUpload" 
              accept=".csv" 
              onChange={handleFileUpload} 
              className="file-input"
            />
            {csvFile && <span className="file-name">{csvFile.name}</span>}
          </div>
          {excelData.length > 0 && (
            <div className="excel-preview-info">
              <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
              <button 
                onClick={handleBulkSubmit} 
                className="submit-button bulk-upload-button"
                disabled={isLoading}
              >
                {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
              </button>
              <button 
                onClick={resetCsvUpload} 
                className="clear-excel-button"
                disabled={isLoading}
              >
                Xóa dữ liệu CSV
              </button>
            </div>
          )}
        </section>
      )}
    </div>
  );
}

export default KhaiBaoCoSo;
